// 1. MENGAMBIL SEMUA BARIS DATA AKTIVITAS (Menggunakan .all())
const allActivities = $('Get many rows').all() || [];

// Inisialisasi variabel untuk data umum
let steps = 0;
let codingHours = 0;
let screenTime = 0;
let restingHeartRate = null;
let stressLevelScore = null;

// Array khusus untuk menampung semua sesi tidur yang ditemukan
const sleepSessions = [];

if (allActivities.length > 0) {
  // Ambil data non-tidur dari baris pertama saja agar tidak ganda
  const primaryData = allActivities[0].json || {};
  steps = primaryData.steps_count || 0;
  codingHours = primaryData.wakatime_coding_hours || 0;
  screenTime = primaryData.screen_time_minutes || 0;
  restingHeartRate = primaryData.resting_heart_rate;
  stressLevelScore = primaryData.stress_level_score;

  // Loop semua baris untuk mencari dan memisahkan setiap sesi tidur
  for (const row of allActivities) {
    const data = row.json || {};
    let sleepMinutes = data.sleep_duration_minutes || 0;

    // Jika menit durasi 0, hitung manual dari session_start & session_end
    if (sleepMinutes === 0 && data.session_start && data.session_end) {
      const start = new Date(data.session_start);
      const end = new Date(data.session_end);
      sleepMinutes = Math.round((end - start) / (1000 * 60));
    }

    // Hanya masukkan ke list jika ada tipe tidur atau durasi tidurnya valid
    if (data.sleep_type || sleepMinutes > 0) {
      const type = data.sleep_type || 'Tidur';
      const deepSleep = data.deep_sleep_minutes;

      // Pengondisian ideal: Gabungkan deep sleep ke dalam baris tipe tidur jika datanya ada dan tidak 0
      if (deepSleep !== null && deepSleep !== undefined && deepSleep > 0) {
        sleepSessions.push(`- Status Tidur: ${type} (${sleepMinutes} menit, Nyenyak: ${deepSleep} menit)`);
      } else {
        sleepSessions.push(`- Status Tidur: ${type} (${sleepMinutes} menit)`);
      }
    }
  }
}

// 2. MENGAMBIL DAN MENGHITUNG DATA KEUANGAN (Node Saat Ini)
const financialData = $input.all();
let totalPengeluaran = 0;
let totalPemasukan = 0;

for (const item of financialData) {
  if (item.json.amount) {
    if (item.json.transaction_type === "EXPENSE") {
      totalPengeluaran += item.json.amount;
    } else if (item.json.transaction_type === "INCOME") {
      totalPemasukan += item.json.amount;
    }
  }
}

// 3. MENYUSUN OUTPUT PROMPT
const promptLines = [
  `Data Hari Ini:`,
  `- Langkah kaki: ${steps} langkah`,
  `- Jam Coding: ${codingHours} jam`,
  `- Waktu Layar: ${screenTime} menit`
];

// Masukkan semua data tidur yang sudah dipisah ke dalam prompt
if (sleepSessions.length > 0) {
  promptLines.push(...sleepSessions);
} else {
  promptLines.push(`- Status Tidur: Tidak ada data tidur`);
}

// Pengondisian dinamis untuk Heart Rate dan Stress Level (jika tidak null)
if (restingHeartRate !== null && restingHeartRate !== undefined) {
  promptLines.push(`- Detak Jantung Istirahat: ${restingHeartRate} bpm`);
}

if (stressLevelScore !== null && stressLevelScore !== undefined) {
  promptLines.push(`- Tingkat Stres: ${stressLevelScore}/100`);
}

// Tambahkan data keuangan di bagian akhir
promptLines.push(`- Total Pemasukan: Rp${totalPemasukan.toLocaleString('id-ID')}`);
promptLines.push(`- Total Pengeluaran: Rp${totalPengeluaran.toLocaleString('id-ID')}`);

// Menggabungkan semua baris menjadi satu string teks
const promptData = promptLines.join('\n');

return [{
  json: {
    raw_prompt: promptData
  }
}];

